  ('elementary-d0d1b9a2-moex-00838', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年初買了500隻山羊，準備未來生產羊奶出售，每隻山羊市價為$30,000，並須支付市場至 牧場之運費$20,000。甲公司估計若將該批山羊立即出售，應支付交易成本$5,000 及牧場至市場之運費 $20,000。X1年甲公司共花費$100,000的飼養費、$200,000的人事支出，X1年底每隻山羊的「公允價值 減出售成本」為$45,000。甲公司對於生物資產採用公允價值模式衡量，請問「生產性生物資產－山羊」 於X1年初原始認列之金額為多少？', '["$25,000", "$45,000", "$14,975,000", "$15,020,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00839', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '企業因過去事件而負有現時義務，很有可能需要流出具經濟效益之資源以清償該義務，且該義務之金額 能可靠估計時，該義務屬：', '["或有資產", "或有負債", "負債準備", "確定負債"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00840', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司出售一台客製化工具機械，並提供 1 年期零件更換之保證型保固服務。根據估計，未發生故障的 機率為20%，更換1個零件的機率為40%，更換2個零件的機率為30%，更換3個零件的機率為10%， 每個零件更換成本為$30,000。關於該保固應認列之負債準備金額為何？', '["$0", "$30,000", "$39,000", "$60,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00841', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日支付現金$1,000,000購買設備，估計耐用年限為5年，該公司預計5年後將支出 $50,000拆除該設備（該公司認為10%為適當折現率，$50,000的現值為$31,000），則甲公司X2年度相 關之利息費用為：', '["$0", "$3,410", "$19,000", "$100,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
