  ('elementary-d0d1b9a2-moex-00844', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列敘述何者錯誤？', '["趨勢百分比增加代表企業經營有利", "結構分析的目的在分析企業資產、資本及盈餘結構", "將不同年度報表內之相關財務資訊加以分析係屬動態分析", "將財務報表上各項目按其金額占總額的百分比列示為靜態分析"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
